class PaymentActivity : AppCompatActivity() {

    private lateinit var billingClient: BillingClient
    private val viewModel by lazy { ViewModelProvider(this).get(PaymentViewModel::class.java) }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_payment)

        initBillingClient()
        observePaymentStatus()

        // Example of initiating a purchase
        viewModel.initiatePurchase("product_id")
    }

    private fun initBillingClient() {
        billingClient = BillingClient.newBuilder(this).setListener(
            PurchasesUpdatedListener { responseCode, purchases ->
                if (responseCode == BillingClient.BillingResponseCode.OK && purchases != null) {
                    for (purchase in purchases) {
                        handlePurchase(purchase)
                    }
                } else if (responseCode == BillingClient.BillingResponseCode.USER_CANCELED) {
                    Log.d("PaymentActivity", "User canceled the purchase")
                } else {
                    Log.e("PaymentActivity", "Error purchasing item")
                }
            }
        ).enablePendingPurchases().build()

        billingClient.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(responseCode: Int) {
                if (responseCode == BillingClient.BillingResponseCode.OK) {
                    Log.d("PaymentActivity", "Billing client is ready. Querying for in-app purchases.")
                    querySkuDetails()
                }
            }

            override fun onBillingServiceDisconnected() {
                // Try to restart the connection
                billingClient.startConnection(this)
            }
        })
    }

    private fun querySkuDetails() {
        val skuList = ArrayList<String>()
        skuList.add("product_id") // Replace with actual product ID

        val params = SkuDetailsParams.newBuilder()
        params.setSkusList(skuList).setType(BillingClient.SkuType.INAPP)

        billingClient.querySkuDetailsAsync(params.build()) { result ->
            if (result.responseCode == BillingClient.BillingResponseCode.OK) {
                result.skuDetailsList?.let { skuDetailsList ->
                    for (skuDetails in skuDetailsList) {
                        Log.d("PaymentActivity", "Product: ${skuDetails.title}, Price: ${skuDetails.price}")
                        viewModel.skuDetails = skuDetails
                    }
                }
            } else {
                Log.e("PaymentActivity", "Error querying SKU details")
            }
        }
    }

    private fun handlePurchase(purchase: Purchase) {
        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED && !purchase.isAcknowledged) {
            GlobalScope.launch(Dispatchers.IO) {
                acknowledgePurchase(purchase)
            }
        }
    }

    private suspend fun acknowledgePurchase(purchase: Purchase) {
        val ackResult = billingClient.acknowledgePurchase(AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken).build())

        if (ackResult.responseCode == BillingClient.BillingResponseCode.OK) {
            Log.d("PaymentActivity", "Purchase acknowledged successfully")
            // Update UI or notify user of successful purchase
        } else {
            Log.e("PaymentActivity", "Failed to acknowledge purchase")
        }
    }

    private fun observePaymentStatus() {
        viewModel.paymentSuccess.observe(this, Observer { isSuccess ->
            if (isSuccess) {
                // Handle success scenario
            } else {
                // Handle failure scenario
            }
        })
    }
}

